mapper.sql:
WHERE 1 = 1

    AND u.role = #{request.role}


    AND u.status = #{request.status}


    AND ua.auth_provider = #{request.authProvider}


    AND (
        u.email LIKE CONCAT('%', #{request.keyword}, '%')
        OR u.nickname LIKE CONCAT('%', #{request.keyword}, '%')
        OR ua.login_id LIKE CONCAT('%', #{request.keyword}, '%')
    )
